import type { ThemePaletteColors } from "../types/theme.ts";

/** Hardcoded ANSI debug palette for visual testing of palette slot assignments. */
export const debugPalette: ThemePaletteColors = {
    black: "#000000",
    gray: "#808080",

    darkRed: "#8B0000",
    red: "#FF0000",

    darkYellow: "#B8860B",
    yellow: "#FFFF00",

    darkGreen: "#006400",
    green: "#00FF00",

    darkCyan: "#008B8B",
    cyan: "#00FFFF",

    darkBlue: "#00008B",
    blue: "#0080FF",

    darkMagenta: "#8B008B",
    magenta: "#FF00FF",

    lightGray: "#D3D3D3",
    white: "#FFFFFF",
};

export function createPalette(
    colors: ThemePaletteColors,
    opts?: {
        debug?: boolean;
        override?: (palette: ThemePaletteColors) => ThemePaletteColors;
    },
): ThemePaletteColors {
    if (opts?.debug) return debugPalette;
    if (opts?.override) return opts.override(colors);
    return colors;
}

import type { HexColor } from "./colors.ts";

/** Primary color scale with dark (d), medium (m), and light (l) ranges. */
export interface ThemePrimaryColors {
    /** Darkest background */
    d10: HexColor;
    d20: HexColor;
    d30: HexColor;
    d40: HexColor;

    /** Mid-range tones */
    m10: HexColor;
    m20: HexColor;
    m30: HexColor;
    m40: HexColor;

    /** Lightest foreground */
    l10: HexColor;
    l20: HexColor;
    l30: HexColor;
    l40: HexColor;
}

/** 16-color terminal palette. */
export interface ThemePaletteColors {
    black: HexColor;
    gray: HexColor;
    darkRed: HexColor;
    red: HexColor;
    darkGreen: HexColor;
    green: HexColor;
    darkYellow: HexColor;
    yellow: HexColor;
    darkBlue: HexColor;
    blue: HexColor;
    darkMagenta: HexColor;
    magenta: HexColor;
    darkCyan: HexColor;
    cyan: HexColor;
    lightGray: HexColor;
    white: HexColor;
}

/** Minimal accent colors used by MNML collection themes. */
export interface ThemeAccentColors {
    a10: HexColor;
    a20: HexColor;
    a30?: HexColor;
    a40?: HexColor;
}

/** Semantic feedback colors for UI states. */
export interface ThemeFeedbackColors {
    negative: HexColor;
    success: HexColor;
    info: HexColor;
    warning: HexColor;
}

/** Options object passed to all create-ui and create-syntax functions. */
export interface ThemeCreatorOptions {
    primaries: ThemePrimaryColors;
    palette: ThemePaletteColors;
    feedback: ThemeFeedbackColors;
    accents: ThemeAccentColors;
}

/** Background colors for UI elements. */
interface ThemeUiBackgroundColors {
    default: HexColor;
    panel: HexColor;
    float: HexColor;
    active: HexColor;
    disabled: HexColor;
    hover: HexColor;
    selection: HexColor;
    search: HexColor;
    contrast: HexColor;
    negative: HexColor;
    warn: HexColor;
    info: HexColor;
    hint: HexColor;
    positive: HexColor;
    add: HexColor;
    delete: HexColor;
    modify: HexColor;
}

/** Foreground colors for UI elements. */
interface ThemeUiForegroundColors {
    default: HexColor;
    subtle: HexColor;
    accent: HexColor;
    disabled: HexColor;
    contrast: HexColor;
    negative: HexColor;
    warn: HexColor;
    info: HexColor;
    hint: HexColor;
    positive: HexColor;
    add: HexColor;
    delete: HexColor;
    modify: HexColor;
}

/** UI color tokens split into background and foreground groups. */
export interface ThemeUiColors {
    bg: ThemeUiBackgroundColors;
    fg: ThemeUiForegroundColors;
}

/** Syntax highlighting color tokens for all language constructs. */
export interface ThemeSyntaxColors {
    variable: {
        default: HexColor;
        builtin: HexColor;
        parameter: HexColor;
        member: HexColor;
    };
    string: {
        default: HexColor;
        doc: HexColor;
        regexp: HexColor;
        escape: HexColor;
    };
    boolean: {
        default: HexColor;
    };
    number: {
        default: HexColor;
    };
    property: {
        default: HexColor;
    };
    constant: {
        default: HexColor;
        builtin: HexColor;
    };
    module: {
        default: HexColor;
    };
    type: {
        default: HexColor;
        builtin: HexColor;
    };
    attribute: {
        default: HexColor;
        builtin: HexColor;
    };
    func: {
        default: HexColor;
        builtin: HexColor;
        method: HexColor;
    };
    constructor: {
        default: HexColor;
    };
    operator: {
        default: HexColor;
    };
    keyword: {
        default: HexColor;
        import: HexColor;
        export: HexColor;
    };
    punctuation: {
        default: HexColor;
        delimiter: HexColor;
        bracket: HexColor;
        special: HexColor;
    };
    comment: {
        default: HexColor;
        doc: HexColor;
        todo: HexColor;
        error: HexColor;
        warn: HexColor;
        info: HexColor;
        hint: HexColor;
    };
    tag: {
        default: HexColor;
