import type { ThemeAccentColors, ThemeDefinition, ThemePrimaryColors } from "../../types/theme.ts";
import { themeKeyMetaMap } from "../../types/themes.ts";
import { oklch } from "../../utils/color.ts";

import createFeedback from "./create-feedback-dark.ts";
import createPalette from "./create-palette-dark.ts";
import createSyntax from "./create-syntax-dark.ts";
import createUi from "./create-ui-dark.ts";

const meta = themeKeyMetaMap["black-atom-default-dark"];

const primaries: ThemePrimaryColors = {
    d10: oklch(0.12, 0.010, 240),
    d20: oklch(0.16, 0.010, 240),
    d30: oklch(0.20, 0.010, 240),
    d40: oklch(0.24, 0.010, 240),

    m10: oklch(0.38, 0.015, 240),
    m20: oklch(0.45, 0.015, 240),
    m30: oklch(0.52, 0.015, 240),
    m40: oklch(0.59, 0.015, 240),

    l10: oklch(0.82, 0.008, 240),
    l20: oklch(0.86, 0.008, 240),
    l30: oklch(0.90, 0.008, 240),
    l40: oklch(0.94, 0.005, 240),
};

const accents: ThemeAccentColors = {
    a10: oklch(0.72, 0.13, 190),
    a20: oklch(0.64, 0.13, 190),
    a30: oklch(0.68, 0.12, 55),
    a40: oklch(0.60, 0.10, 55),
};

const palette = createPalette(primaries, {
    override: (palette) => ({
        ...palette,
        cyan: accents.a10,
