import { oklch, formatRgb, parse } from "npm:culori";

/**
 * Extracts text-non-background colors from a cropped code area screenshot.
 * Uses ImageMagick to sample a cropped region and identify distinct colors
 * that differ from the dominant background.
 */
async function extractSyntaxColors(imagePath: string, label: string) {
  // First, get the background color from a large uniform area
  const bgCmd = new Deno.Command("magick", {
    args: [imagePath, "-crop", "120x120+300+300", "-resize", "1x1", "-alpha", "off", "txt:-"],
    stdout: "piped",
    stderr: "piped",
  });
  const bgOut = await bgCmd.output();
  const bgText = new TextDecoder().decode(bgOut.stdout);
  const bgHex = bgText.match(/#([0-9A-Fa-f]{6})/)?.[0];
  if (!bgHex) { console.log(`${label}: Could not determine bg`); return; }

  const bg = parse(bgHex) as { r: number; g: number; b: number } | null;
  const bgOk = oklch(bgHex);
  if (!bg || !bgOk) { console.log(`${label}: Could not parse bg`); return; }
  console.log(`${label} Editor BG: ${bgHex}  OKLCH(${(bgOk as any).l?.toFixed(3)}, ${(bgOk as any).c?.toFixed(3)}, ${(bgOk as any).h?.toFixed(1)})`);

  // Crop to the code area, resize small, get quantized colors with pixel counts
  const cmd = new Deno.Command("magick", {
    args: [
      imagePath, "-crop", "2000x1800+300+100", "-resize", "200x180",
      "-colors", "24", "-unique-colors", "-alpha", "off",
      "-format", "%c", "histogram:info:-",
    ],
    stdout: "piped",
    stderr: "piped",
  });
  const out = await cmd.output();
  const text = new TextDecoder().decode(out.stdout);
  const lines = text.trim().split("\n");

  // Parse histogram output
  // Format: "   1234: (r,g,b,...) #HEX  srgb(...)"
  const colors: Array<{ hex: string; count: number; l: number; c: number; h: number; distance: number }> = [];

  for (const line of lines) {
    const match = line.match(/^\s*(\d+):.*?\s+(#[0-9A-Fa-f]{6,8})/);
    if (!match) continue;
    const count = parseInt(match[1]);
    let hex = match[2].substring(0, 7);

    try {
      const c = oklch(hex) as any;
      if (!c || !c.l) continue;

      // Distance from background in OKLCH space (weighted)
      const dl = c.l - (bgOk as any).l;
      const dc = (c.c ?? 0) - ((bgOk as any).c ?? 0);
      const dh = ((c.h ?? 0) - ((bgOk as any).h ?? 0)) * 0.1;
      const distance = Math.sqrt(dl * dl * 100 + dc * dc * 10 + dh * dh);

      colors.push({ hex, count, l: c.l, c: c.c ?? 0, h: c.h ?? 0, distance });
    } catch(_) {}
  }

  // Sort by pixel count
  colors.sort((a, b) => b.count - a.count);

  const total = colors.reduce((s, c) => s + c.count, 0);

  console.log(`\n${label} — All ${colors.length} quantized colors:`);
  for (const c of colors) {
    const pct = (c.count / total * 100).toFixed(1);
    console.log(`  ${c.hex}  OKLCH(${c.l.toFixed(3)}, ${c.c.toFixed(3)}, ${c.h.toFixed(1)})  dist=${c.distance.toFixed(1)}  ${pct}%`);
  }

  // Text colors = non-bg colors with significant lightness diff
  const textColors = colors.filter(c => c.distance > 3);
  console.log(`\n${label} — Likely syntax/text colors (dist > 3):`);
  for (const c of textColors) {
    console.log(`  ${c.hex}  OKLCH(${c.l.toFixed(3)}, ${c.c.toFixed(3)}, ${c.h.toFixed(1)})  ${c.count}px`);
  }

  // Group by hue to find accent families
  const hueFamilies: Record<string, Array<typeof colors[0]>> = {};
  for (const c of colors) {
    if (c.c < 0.005 || c.distance < 1) continue; // skip near-gray backgrounds
    const bucket = Math.round(c.h / 30) * 30;
    const key = `${bucket}`;
    if (!hueFamilies[key]) hueFamilies[key] = [];
    hueFamilies[key].push(c);
  }

  console.log(`\n${label} — Color families (by hue):`);
  for (const [hue, cols] of Object.entries(hueFamilies).sort((a, b) => parseInt(a[0]) - parseInt(b[0]))) {
    const avg = cols.reduce((s, c) => ({ l: s.l + c.l * c.count, c: s.c + c.c * c.count, count: s.count + c.count }), { l: 0, c: 0, count: 0 });
    avg.l /= avg.count;
    avg.c /= avg.count;
    console.log(`  Hue ${hue}° (${cols.length} colors): avg OKLCH(${avg.l.toFixed(3)}, ${avg.c.toFixed(3)}, count: ${avg.count}px)`);
    for (const c of cols) {
      console.log(`    ${c.hex}  OKLCH(${c.l.toFixed(3)}, ${c.c.toFixed(3)}, ${c.h.toFixed(1)})  ${c.count}px`);
    }
  }
  console.log("");
}

const images = [
  { path: "docs/old_screenshots/default_dark.png", label: "Default Dark" },
