}

for (const img of images) {
  await extractSyntaxColors(img.path, img.label);
}

import { oklch, formatHex } from "npm:culori";

interface FlatImage {
  path: string;
  label: string;
  bgColor: string;
  bgOk: { l: number; c: number; h: number };
}

async function getBgColor(path: string): Promise<{ hex: string; l: number; c: number; h: number } | null> {
  const cmd = new Deno.Command("magick", {
    args: [path, "-crop", "120x120+300+300", "-resize", "1x1", "-alpha", "off", "txt:-"],
    stdout: "piped",
    stderr: "piped",
  });
  const out = await cmd.output();
  const text = new TextDecoder().decode(out.stdout);
  const hex = text.match(/#([0-9A-Fa-f]{6})/)?.[0];
  if (!hex) return null;
  const ok = oklch(hex) as any;
  if (!ok) return null;
  return { hex, l: ok.l, c: ok.c ?? 0, h: ok.h ?? 0 };
}

async function samplePixel(path: string, x: number, y: number): Promise<{ hex: string; l: number; c: number; h: number } | null> {
  const cmd = new Deno.Command("magick", {
    args: [path, "-crop", "1x1+" + x + "+" + y, "-alpha", "off", "txt:-"],
    stdout: "piped",
    stderr: "piped",
  });
  const out = await cmd.output();
  const text = new TextDecoder().decode(out.stdout);
  const hex = text.match(/#([0-9A-Fa-f]{6})/)?.[0];
  if (!hex) return null;
  const ok = oklch(hex) as any;
  if (!ok) return null;
  return { hex, l: ok.l, c: ok.c ?? 0, h: ok.h ?? 0 };
}

function distance(c: { l: number; c: number; h: number }, bg: { l: number; c: number; h: number }): number {
  return Math.sqrt((c.l - bg.l) ** 2 * 100 + (c.c - bg.c) ** 2 * 10 + ((c.h - bg.h) / 360) ** 2 * 50);
}

async function examineLine(path: string, y: number, label: string, bg: { l: number; c: number; h: number }) {
  const samples: Array<{ x: number; hex: string; l: number; c: number; h: number }> = [];
  for (let x = 300; x < 3500; x += 5) {
    const p = await samplePixel(path, x, y);
    if (p) {
      const d = distance(p, bg);
      if (d > 2) { // non-background
        // Deduplicate — keep last sample of similar color
        const prev = samples.length > 0 ? samples[samples.length - 1] : null;
        if (!prev || Math.abs(prev.x - x) > 4 || distance(p, { l: prev.l, c: prev.c, h: prev.h }) > 1) {
          samples.push(p);
        }
      }
    }
  }

  console.log(`\n${label} y=${y}: ${samples.length} distinct color runs`);
  for (const s of samples) {
    console.log(`  x=${s.x}  ${s.hex}  OKLCH(${s.l.toFixed(3)}, ${s.c.toFixed(3)}, ${s.h.toFixed(1)})`);
  }
  return samples;
}

// Flatten and analyze
const images = [
  { path: "docs/old_screenshots/default_dark.png", label: "Default Dark" },
  { path: "docs/old_screenshots/default_dark_dimmed.png", label: "Dark Dimmed" },
  { path: "docs/old_screenshots/default_light.png", label: "Default Light" },
  { path: "docs/old_screenshots/default_light_dimmed.png", label: "Light Dimmed" },
];

for (const img of images) {
  const flatPath = img.path.replace(".png", "_flat.png");
  await new Deno.Command("magick", { args: [img.path, "-background", "black", "-flatten", flatPath] }).output();

  const bg = await getBgColor(flatPath);
  if (!bg) continue;

  console.log("=".repeat(70));
  console.log(img.label);
  console.log("Editor BG:", bg.hex, `OKLCH(${bg.l.toFixed(3)}, ${bg.c.toFixed(3)}, ${bg.h.toFixed(1)})`);

  // Examine multiple lines
  for (const y of [100, 150, 200, 250, 300, 350, 400, 450, 500, 550, 600]) {
    await examineLine(flatPath, y, img.label, bg);
  }
}

