import type { ThemePaletteColors, ThemePrimaryColors } from "../../types/theme.ts";
import { createPalette } from "../create-palette.ts";

export default function (
    primaries: ThemePrimaryColors,
    opts?: Parameters<typeof createPalette>[1],
): ThemePaletteColors {
    return createPalette({
        black: primaries.d40,
        gray: primaries.m20,

        darkRed: primaries.m40,
        red: primaries.m40,

        darkYellow: primaries.m30,
        yellow: primaries.m30,

        darkGreen: primaries.m40,
        green: primaries.m40,

        darkCyan: primaries.m40,
        cyan: primaries.m40,

        darkBlue: primaries.m20,
        blue: primaries.m20,

        darkMagenta: primaries.m30,
        magenta: primaries.m30,

        lightGray: primaries.l20,
        white: primaries.l30,
    }, opts);
}

import type { ThemePaletteColors, ThemePrimaryColors } from "../../types/theme.ts";
import { createPalette } from "../create-palette.ts";

export default function (
    primaries: ThemePrimaryColors,
    opts?: Parameters<typeof createPalette>[1],
): ThemePaletteColors {
    return createPalette({
        black: primaries.d20,
        gray: primaries.m10,

        darkRed: primaries.m20,
        red: primaries.m20,

        darkYellow: primaries.m30,
        yellow: primaries.m30,

        darkGreen: primaries.m40,
        green: primaries.m40,

        darkCyan: primaries.m30,
        cyan: primaries.m30,

        darkBlue: primaries.m20,
        blue: primaries.m20,

        darkMagenta: primaries.m30,
        magenta: primaries.m30,

        lightGray: primaries.m40,
        white: primaries.l10,
    }, opts);
}

import type { ThemeCreatorOptions, ThemeUiColors } from "../../types/theme.ts";
import { tint } from "../../utils/color.ts";

export default function (
    { primaries, feedback, accents }: ThemeCreatorOptions,
): ThemeUiColors {
    function t(color: string) {
        return tint({ color, with: primaries.d10, amount: 0.40 });
    }

    const sharedFg = {
        negative: feedback.negative,
        info: feedback.info,
        hint: feedback.warning,
        warn: feedback.warning,
        positive: feedback.success,
        add: feedback.success,
        delete: feedback.negative,
        modify: feedback.info,
    };

    const sharedBg = {
        negative: t(feedback.negative),
        info: t(feedback.info),
        hint: t(feedback.warning),
        warn: t(feedback.warning),
        positive: t(feedback.success),
        add: t(feedback.success),
        delete: t(feedback.negative),
        modify: t(feedback.info),
    };

    return {
        bg: {
            default: primaries.d20,
            panel: primaries.d10,
            float: primaries.d10,
            active: primaries.d30,
            disabled: primaries.d40,
            hover: primaries.d30,
            selection: primaries.d40,
            search: primaries.d40,
            contrast: primaries.l10,
            ...sharedBg,
        },
        fg: {
            default: primaries.l30,
            subtle: primaries.m30,
            accent: accents.a10,
            disabled: primaries.m20,
            contrast: primaries.d20,
            ...sharedFg,
        },
    };
}

import type { ThemeCreatorOptions, ThemeUiColors } from "../../types/theme.ts";
import { tint } from "../../utils/color.ts";

export default function (
    { primaries, feedback, accents }: ThemeCreatorOptions,
): ThemeUiColors {
    function t(color: string) {
        return tint({ color, with: primaries.l40 });
    }

    const sharedFg = {
        negative: feedback.negative,
        info: feedback.info,
        hint: feedback.warning,
        warn: feedback.warning,
        positive: feedback.success,
        add: feedback.success,
        delete: feedback.negative,
        modify: feedback.info,
    };

    const sharedBg = {
        negative: t(feedback.negative),
        info: t(feedback.info),
        hint: t(feedback.warning),
        warn: t(feedback.warning),
        positive: t(feedback.success),
        add: t(feedback.success),
        delete: t(feedback.negative),
        modify: t(feedback.info),
    };

    return {
        bg: {
            default: primaries.l30,
            panel: primaries.l20,
            float: primaries.l20,
            active: primaries.l40,
            disabled: primaries.l10,
            hover: primaries.l10,
            selection: primaries.l10,
            search: primaries.l10,
            contrast: primaries.d40,
            ...sharedBg,
        },
        fg: {
            default: primaries.d20,
            subtle: primaries.m10,
            accent: accents.a10,
            disabled: primaries.m30,
            contrast: primaries.l20,
            ...sharedFg,
        },
    };
}
